module.exports = /*#__PURE__*/JSON.parse('{"hero":{"name":"Stephen Asatsa, PhD","eyebrow":"Psychologist, Academic, Research Leader","headline":"Evidence-based psychological care and culturally grounded scholarship for people and institutions shaping healthier futures.","subheadline":"Dr. Stephen Asatsa is a Kenyan psychologist, senior lecturer, and Head of Department of Psychology at the Catholic University of Eastern Africa with deep experience in teaching, research, mentorship, and professional practice.","primaryCta":{"label":"Book a Consultation","href":"/services#booking"},"publicationsCta":{"label":"See Publications","href":"https://scholar.google.com/citations?user=nBzSCvUAAAAJ&hl=en"},"secondaryCta":{"label":"Download CV","href":"/Stephen_Asatsa-CV-2025.pdf"}},"aboutShort":"Dr. Stephen is a senior Lecturer and Head of Department of Psychology at the Catholic University of Eastern Africa with extensive experience in academic strategy and research. He is an experienced Consultant Psychologist registered and licensed by the Kenya Counselors and Psychologists Board and co-founder of BeautifulMind Consultants, a Kenyan mental health social enterprise.","aboutFull":["Dr. Stephen is a senior Lecturer and Head of Department of Psychology at the Catholic University of Eastern Africa with extensive experience in academic strategy and research. Proven track record as a Lecturer of Psychology, excelling in teaching, research, and student mentorship.","He is an experienced Consultant Psychologist registered and licensed by the Kenya Counselors and Psychologists Board and co-founder of BeautifulMind Consultants, a Kenyan mental health social enterprise.","He serves on the governing Council of the Society for Research in Child Development (SRCD). He is the Africa regional representative for the European Association of Personality Psychology (EAPP). He is the e-newsletter editor for the International Society for the Study of Behavioral Development (ISSBD).","He is also a review editor for Frontiers in Psychology and Frontiers in Reproductive Health. His research interests span Indigenous knowledge systems, decolonization of psychology, thanatology, and cultural evolution. He is a strong advocate for the indigenization of psychological practice."],"quote":{"text":"We are all in the gutter, but some of us are looking at the stars. Everyone has problems to deal with, but the people who are mesmerized by the beauty of their dreams are the ones who actually live life to the fullest.","author":"Oscar Wilde"},"services":[{"title":"Psychotherapy","description":"Thoughtful support for stress, burnout, grief and loss, trauma, adolescent difficulties, relationship challenges, anxiety, depression, and life transitions.","bullets":["Individual support","Couples and family guidance","Premarital and career counseling"]},{"title":"Consulting","description":"Professional psychological consultation for organizations, institutions, and teams navigating change, wellbeing, leadership, and workplace resilience.","bullets":["Corporate wellbeing","Academic strategy","Advisory engagements"]},{"title":"Research Leadership","description":"Research design, collaboration, and dissemination for interdisciplinary projects rooted in local context and rigorous scholarship.","bullets":["Grant-aligned research support","Research mentorship","Publication strategy"]},{"title":"Mentorship","description":"Guidance for students, early-career researchers, and professionals building meaningful careers in psychology and allied disciplines.","bullets":["Graduate supervision","Career development","Writing and publishing support"]},{"title":"Corporate Training","description":"Engaging sessions for institutions looking to strengthen mental health literacy, coping skills, and culture-sensitive human support systems.","bullets":["Mental health education","Trauma-informed practice","Leadership workshops"]},{"title":"Booking Support","description":"A dedicated consultation flow for people seeking one-on-one guidance and support through an accessible booking process.","bullets":["Calendly integration","Virtual counseling","Professional follow-up"]}],"researchProjects":[{"title":"Traditional Luhya mourning rituals: A cultural evolutionary approach to understanding community wellbeing, cooperation, cultural transmission, and cultural resilience in a Kenyan Indigenous community","summary":"A major interdisciplinary project exploring the therapeutic value of Indigenous mourning rituals, their role in cooperation, and how they support cultural transmission and resilience in western Kenya.","category":"Decolonizing Psychology","status":"Active","funding":"Templeton Foundation and Cultural Evolution Society","details":["The project studies how globalization affects the practice and transmission of Indigenous mourning rituals in the Luhya community.","It uses qualitative and quantitative methods including focus groups, interviews, behavioral observations, and psychometric tools.","The work aims to produce peer-reviewed outputs, op-eds, training materials, and policy briefs for Kenyan mental health practice."],"link":"https://ces-transformationfund.org/our-projects/traditional-luhya-mourning-rituals/"},{"title":"The Africa Long Life Study: A longitudinal exploration of the psychological development of young adults in Kenya, Namibia and South Africa","summary":"A five-year longitudinal collaborative study examining personality traits, mental health, and the psychological development of emerging adults across multiple African contexts.","category":"Developmental Psychology","status":"Active","funding":"Swiss National Science Foundation and the University of Zurich","details":["The Kenyan sample follows 800 eighteen-year-olds from across Kenya with data collection every six months.","The study compares universal and culturally specific aspects of psychological development across Kenya, Namibia, and South Africa.","Findings are intended to support counsellors, educators, and policy makers working with emerging adults."],"link":"https://www.uzh.ch/blog/africalonglifestudy/team/"},{"title":"Impact of Covid 19 Experiences on Emotional Regulation among Adolescents in 6 Countries","summary":"A cross-country study investigating how Covid-19 disruptions affected religiosity, character strengths, and emotional regulation among adolescents in Kenya, Nigeria, Ethiopia, Namibia, the Philippines, and Australia.","category":"Mental Health","status":"Collaborative","funding":"Templeton Foundation and the International Consortium of Developmental Science Societies","details":["The project examines the mediating role of religiosity and character strengths during pandemic disruption.","It addresses school closure, stress, meaning-making resources, and adolescent coping strategies during recovery.","The collaboration includes partners from Griffith University, the University of the Philippines, Addis Ababa University, and Nnamdi Azikiwe University."],"link":"https://www.fjcolab.org/sra-covid-19-early-career-global-scholars-program"},{"title":"Covid-19 Pandemic-Related Impacts and Severity of Substance Use Disorder Symptoms among Patients in Selected Rehabilitation Centers in Nairobi, Kenya","summary":"Research on how pandemic containment measures shaped addiction severity and treatment conditions among residential rehabilitation patients in Nairobi.","category":"Mental Health","status":"Ongoing","funding":"International Consortium of Universities for Drug Demand Reduction (ICUDDR)","details":["The study examined addiction severity before and during the pandemic among patients in selected rehabilitation centres.","It used sociodemographic tools, the Epidemic-Pandemic Impacts Inventory, and a Modified Addiction Severity Index.","The findings were designed to inform treatment-program adjustment during and after the pandemic."],"link":"https://nida.nih.gov/international/news/nida-supported-mini-grant-projects-featured-icuddr-annual-meeting"},{"title":"Global research on work addiction","summary":"Contribution to international work on macro-, meso-, and micro-level drivers of work addiction and associated health outcomes.","category":"Global Collaboration","status":"Collaborative","funding":"National Science Centre in Poland","details":["This stream focuses on the social and structural dimensions of work addiction and related health problems."],"link":"https://workaddiction.org/"},{"title":"Global Collaboration on Traumatic Stress","summary":"International work on culture-sensitive trauma assessment and the adaptation of trauma research across contexts.","category":"Trauma Studies","status":"Collaborative","details":["The collaboration centers on culturally sensitive assessment frameworks in psychotrauma research."],"link":"https://www.global-psychotrauma.net/cultural-sensitive-assessment"}],"publications":[{"title":"Stephen Asatsa CV 2025","year":"2025","type":"CV","summary":"Complete professional curriculum vitae including affiliations, appointments, and scholarly activity.","fileUrl":"/Stephen_Asatsa-CV-2025.pdf"},{"title":"Research for Posterity","year":"2024","type":"Presentation","summary":"Research dissemination work focused on preserving scholarship and extending community impact."},{"title":"Afrocentric Psychology and Mourning Rituals","year":"2025","type":"Invited Talk","summary":"A perspective on Afrocentric psychology through Luhya mourning rituals and culturally informed healing frameworks."}],"grants":["Jan 2025: European Association of Personality Psychology Focus Meeting Grant (Euro 10,000)","April 2024: ICUDDR Travel Grant (ICUDDR Conference in Greece, June 22-28, 2024)","March 2024: ISSBD Travel Grant (Portugal Biennial Meeting, June 17-21, 2024)","March 2023: ICUDDR Travel Grant (ISAM Congress in Marrakesh, Morocco, Nov 2-4, 2023)","April 2023: Cultural Evolution Society ACE Grant for scholar mobility (USD 6,000)","March 2023: ICUDDR Travel Grant (NIDA/CPDD Conference, Denver, Colorado, June 17-21, 2023)","Feb 2023: ICUDDR Travel Grant (Chiang Mai, Thailand, August 9-11, 2023)","August 2022: Cultural Evolution Society Cultural Transformation Grant (GBP 89,200)","June 2022: John Templeton Travel Grant (Templeton Annual Meeting, Bahamas)","May 2022: SRA Covid-19 Network Early Career Scholars Fellowship (USD 8,500)","May 2022: ICUDDR Travel Grant (ISSUP Conference, Abu Dhabi)","Feb 2022: National Institute of Drug Abuse Small Grant (USD 5,000)","April 2022: ISSBD Travel Grant (Greece Biennial Meeting)","Oct 2021: Global Academy of Liberal Arts Network Early Career Programme","Sep 2019: SRCD-Jacobs Foundation Series on Social Learning","Feb 2017: ISSBD Travel Fund (South East Asia regional workshop, Hat Yai, Thailand)","Feb 2016: ISSBD Developing Country Fellowship (2016-2018)"],"conferences":["Cultural Evolution Society Capstone Conference, Durham University, UK, September 9-12, 2024","21st European Conference on Personality, Humboldt-Universität, Berlin, Germany, August 6-9, 2024","ICUDDR Conference, Thessaloniki, Greece, June 24-28, 2024","ISSBD Biennial Meeting, Lisbon, Portugal, June 16-20, 2024","The role of culture in post-traumatic sufferings, Collegium Helveticum, Zurich, Switzerland, April 23-24, 2024","The role of dignity, face, and honor cultural logics in intrapersonal, interpersonal, and intergroup processes, Pescara, Italy, April 17-19, 2024","ISAM Congress, Marrakesh, Morocco, November 2-4, 2023","Thailand Addiction Scientific Conference, Chiang Mai University, Thailand, August 9-11, 2023","College on Problems of Drug Dependence Conference, Denver, Colorado, June 17-21, 2023","International Society for the Study of Behavioral Development, Rhodes, Greece, June 19-23, 2022","International Society for Substance Use Professionals Conference, Abu Dhabi, May 12-16, 2022","Society for Research on Adolescence Biennial Meeting, New Orleans, USA, March 3-5, 2022","Society for Research in Child Development Social Learning Workshop, Amsterdam, Netherlands, September 2019","25th Biennial International Society for the Study of Behavioral Development Conference, Gold Coast, Australia, July 2018","1st Pan African Psychology Union Congress, Durban, South Africa, September 2017","South East Asia ISSBD Regional Workshop, Prince of Songkla University, Hat Yai, Thailand, February 2017","24th Biennial ISSBD Conference, Vilnius, Lithuania, July 2016","8th Annual Pan-African PCAF Psychotrauma Conference, Nairobi, Kenya, July 2015","Eastern Africa Regional Conference of Psychology, Kampala, Uganda, November 2013"],"invitedTalks":["Oct 3, 2025: Colloquium on African Psychology - Luhya Traditional Mourning Rituals","July 24, 2025: Publishing Research from Thesis or Dissertation","June 29, 2025: Trauma of Imposed Civilization Seminar","Feb 13, 2025: Towards Afrocentric Psychology - Insights from Luhya Mourning Rituals","Sep 24, 2024: Towards Decolonization of Psychology in Africa - Insights from Luhya Mourning Rituals","May 10, 2023: Colloquium on Trauma and Death, University of Zurich, Switzerland","June 21-27, 2023: Crossing Borders International Staff Week, Antwerp University of Applied Sciences, Belgium"],"awards":[{"title":"Durham University International Research Collaboration Award","year":"2024"},{"title":"Human Relations Area Files Global Scholar","year":"2023","href":"https://hraf.yale.edu/hraf-global-scholar-stephen-asatsa/"},{"title":"ICDSS Covid Global Scholar","year":"2022","href":"http://www.fjcolab.org/srascholars-directory"},{"title":"International Society for the Study of Behavioral Development Developing Country Fellowship","year":"2016-2018"}],"externalProfiles":[{"label":"ORCID","href":"https://orcid.org/0000-0002-1045-2583","description":"Persistent researcher identity and scholarly record."},{"label":"Google Scholar","href":"https://scholar.google.com/citations?user=nBzSCvUAAAAJ&hl=en","description":"Citation profile and indexed academic outputs."},{"label":"ResearchGate","href":"https://www.researchgate.net/profile/Stephen_Asatsa2","description":"Research network profile and project visibility."},{"label":"BeautifulMind Consultants","href":"https://beautifulmind.cc/","description":"Mental health social enterprise co-founded by Dr. Asatsa."}],"media":[{"title":"ICUDDR Conference in Chiang Mai, Thailand","href":"https://www.youtube.com/watch?v=5IXtRFASP1o&list=PLaIB9yTPNvoIc4AonyXfBatsBg-ar8jCR&index=11&t=24s","kind":"Conference presentation","year":"2023","description":"Recorded conference presentation from Chiang Mai highlighting the international substance-use prevention and recovery dialogue."},{"title":"Meet the Funders: Jacobs Foundation Research Opportunities and Fellowship Program","href":"https://www.youtube.com/watch?v=-InDluPgMQE","kind":"Conference interview","description":"Interview and funder-facing conversation connected to research opportunities and fellowship pathways."},{"title":"Death Preparedness","href":"https://web.facebook.com/psychologistvoiceke/videos/3325788907463879/","kind":"Recorded talk","description":"Public talk exploring death preparedness and meaning-making around loss and mourning."},{"title":"Colloquium on African Psychology - Luhya Traditional Mourning Rituals","href":"https://www.youtube.com/watch?v=OvJ_mf5-KxY&t=1225s","kind":"Invited talk","year":"2025","description":"A 2025 invited colloquium centered on African psychology and Luhya mourning rituals."},{"title":"Publishing Research from Thesis or Dissertation","href":"https://www.youtube.com/watch?v=UOjotsZRnKM","kind":"Invited talk","year":"2025","description":"Talk focused on turning graduate research into publishable scholarly work."},{"title":"Trauma of Imposed Civilization Seminar","href":"https://www.youtube.com/watch?v=epLpPrMjVuY","kind":"Invited talk","year":"2025","description":"Seminar presentation on trauma, colonial legacies, and culturally grounded interpretation."},{"title":"Towards Decolonization of Psychology in Africa","href":"https://www.youtube.com/watch?v=-DgeQyw7u-c","kind":"Invited talk","year":"2024","description":"Invited talk delivered in Belfast on decolonization and insights from Luhya mourning rituals."},{"title":"Research for Posterity","href":"https://www.youtube.com/watch?v=kLYfSz5yxfo","kind":"Presentation","description":"Presentation about preserving scholarship and extending research impact for posterity."},{"title":"BIEA Graduate Conference","href":"https://www.youtube.com/watch?v=tr3kOybWU0g","kind":"Conference presentation","description":"Conference talk from the BIEA graduate research context."}],"collaborators":[{"name":"Sheina Lew-Levy, PhD","role":"Co-Investigator","affiliation":"Durham University, UK","summary":"Assistant professor of Psychology at Durham University whose work explores cultural diversity and the evolution of social learning in childhood, including hunter-gatherer societies.","href":"https://foragerchildstudies.wixsite.com/home"},{"name":"Eric J. Ringen","role":"Statistical Consultant","affiliation":"University of Zurich, Switzerland","summary":"Consultant statistician for the mourning rituals project with expertise in Bayesian multilevel modeling and computational workflows in R."},{"name":"Prof. Dr. Amber Gayle Thalmayer","role":"Overall Principal Investigator","affiliation":"University of Zurich","summary":"Leads the Africa Long Life Study across the participating countries with a focus on personality, mental health, and culture."},{"name":"Dr. Elizabeth Shino","role":"Principal Investigator, Namibia","affiliation":"University of Namibia","summary":"Research lead for the Namibia arm of the Africa Long Life Study and a featured collaborator from the original site.","image":"/assets/people/dr-elizabeth-shino.jpg"},{"name":"Prof. Luzelle Naudé","role":"Principal Investigator, South Africa","affiliation":"University of the Free State","summary":"South Africa lead on the Africa Long Life Study and a longstanding academic collaborator.","image":"/assets/people/prof-luzelle-naude.png"}],"testimonials":[{"name":"Prof. Luzelle Naudé","role":"Academic Collaborator","quote":"Stephen brings clarity, compassion, and intellectual depth to both research and mentorship. He is a thoughtful collaborator with a strong grounding in culturally meaningful scholarship.","image":"/assets/people/prof-luzelle-naude.png"},{"name":"Dr. Elizabeth Shino","role":"Professional Colleague","quote":"His work bridges practice and academia in a way that feels rigorous, humane, and deeply relevant to African realities.","image":"/assets/people/dr-elizabeth-shino.jpg"},{"name":"Research Mentee","role":"Early-Career Scholar","quote":"Dr. Asatsa creates space for bold thinking while giving practical guidance that makes research feel possible and purposeful.","image":"/assets/people/asatsa.png"}],"gallery":["https://stephenasatsa.com/wp-content/uploads/2025/04/Asatsa-10-scaled.jpeg","https://stephenasatsa.com/wp-content/uploads/2025/04/Asatsa-8-e1743882336142.jpeg","https://stephenasatsa.com/wp-content/uploads/2025/04/Asatsa-5-e1743878426805.jpeg","https://stephenasatsa.com/wp-content/uploads/2025/04/Asatsa-4.jpeg","https://stephenasatsa.com/wp-content/uploads/2025/04/Asatsa-1-scaled.jpg","https://stephenasatsa.com/wp-content/uploads/2025/04/Asatsa-3.jpeg","https://stephenasatsa.com/wp-content/uploads/2023/06/Belgium-Antwerp-City.-During-a-visit-to-Antwerp-University-of-Applied-Sciences.-Crossing-borders-week-4.jpeg","https://stephenasatsa.com/wp-content/uploads/2023/06/Belgium-Antwerp-City.-During-a-visit-to-Antwerp-University-of-Applied-Sciences.-Crossing-borders-week-1.jpeg","/assets/gallery/asatsa-7.jpeg","/assets/gallery/steve3.jpg","/assets/gallery/awards.jpeg","/assets/gallery/steve15-scaled.jpg","/assets/gallery/project.jpeg"],"contact":{"addressLines":["P.O Box 954 00502","Karen – Nairobi"],"phones":["+254 770 140 889","+254 716 842 028"],"whatsapp":"https://web.whatsapp.com/send?phone=+254716842028","socialLinks":[{"label":"Facebook","href":"https://facebook.com/dr.stephenasatsa"},{"label":"Twitter","href":"https://twitter.com/ASATSAS"},{"label":"X","href":"https://x.com/DAsatsa21589"},{"label":"Instagram","href":"https://www.instagram.com/dr.stephenasatsa/"},{"label":"LinkedIn","href":"https://www.linkedin.com/in/stephen-asatsa-phd-b119837a/"}],"mapEmbed":"https://maps.google.com/maps?q=cuea&t=m&z=10&output=embed&iwloc=near","bookingUrl":"https://calendly.com/booking-stephen/online-counseling"},"blogCategories":["Mental Health","Decolonizing Psychology","Thanatology","Research","Academic Leadership"]}');

